import { CommandHandler, ICommandHandler } from '@nestjs/cqrs';

import { Transactional } from 'libs/database/transactional';

import { EmailAdaptor } from 'src/notification/application/adaptor/email-adaptor';
import { SendEmailCommand } from 'src/notification/application/command/send-email-command';

import { NotificationFactory } from 'src/notification/domain/notification-factory';
import { NotificationRepository } from 'src/notification/domain/notification-repository';

@CommandHandler(SendEmailCommand)
export class SendEmailHandler implements ICommandHandler<
  SendEmailCommand,
  void
> {
  constructor(
    private readonly notificationFactory: NotificationFactory,
    private readonly notificationRepository: NotificationRepository,
    private readonly emailAdaptor: EmailAdaptor,
  ) {}

  @Transactional()
  async execute(command: SendEmailCommand): Promise<void> {
    const notification = this.notificationFactory.create({
      ...command,
      id: this.notificationRepository.newId(),
    });
    await this.notificationRepository.save(notification);
    await this.emailAdaptor.sendEmail(
      command.to,
      command.subject,
      command.content,
    );
  }
}

import type { ICommand, ICommandHandler } from '@nestjs/cqrs';
import { CommandHandler } from '@nestjs/cqrs';
import { InjectRepository } from '@nestjs/typeorm';
import type { Repository } from 'typeorm';

import type { CreateSettingsDto } from '../dtos/create-settings.dto.ts';
import { UserSettingsEntity } from '../user-settings.entity.ts';

export class CreateSettingsCommand implements ICommand {
  constructor(
    public readonly userId: Uuid,
    public readonly createSettingsDto: CreateSettingsDto,
  ) {}
}

@CommandHandler(CreateSettingsCommand)
export class CreateSettingsHandler
  implements ICommandHandler<CreateSettingsCommand, UserSettingsEntity>
{
  constructor(
    @InjectRepository(UserSettingsEntity)
    private userSettingsRepository: Repository<UserSettingsEntity>,
  ) {}

  execute(command: CreateSettingsCommand) {
    const { userId, createSettingsDto } = command;
    const userSettingsEntity =
      this.userSettingsRepository.create(createSettingsDto);

    userSettingsEntity.userId = userId;

    return this.userSettingsRepository.save(userSettingsEntity);
  }
}

import { ForbiddenException, Injectable } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { PassportStrategy } from '@nestjs/passport';
import { ExtractJwt, Strategy } from 'passport-jwt';
import { PrismaService } from 'src/prisma/prisma.service';

@Injectable()
export class WsJwtStrategy extends PassportStrategy(Strategy, 'wsJwt') {
  constructor(
    private readonly prismaService: PrismaService,
    readonly configService: ConfigService,
  ) {
    const JWT_SECRET = configService.get('JWT_SECRET');
    super({
      jwtFromRequest: ExtractJwt.fromUrlQueryParameter('token'),
      secretOrKey: JWT_SECRET,
    });
  }

  async validate(payload: any) {
    const user = await this.prismaService.user.findUnique({
      where: {
        uid: payload.sub,
      },
    });

    if (!user) return false; // no user found
    if (!user.verified) throw new ForbiddenException('Not verified'); // user not verified

    delete user.hash;
    return user;
  }
}

